// ============================================================
// HELPERS
// ============================================================

function parseISO(isoStr) {
  return new Date(isoStr);
}

function toTZ(date, tz) {
  const parts = new Intl.DateTimeFormat('en-US', {
    timeZone: tz,
    year: 'numeric', month: '2-digit', day: '2-digit',
    hour: '2-digit', minute: '2-digit', second: '2-digit',
    hour12: false
  }).formatToParts(date);
  const get = type => parts.find(p => p.type === type).value;
  return {
    year: parseInt(get('year')),
    month: parseInt(get('month')),
    day: parseInt(get('day')),
    hour: parseInt(get('hour')),
    minute: parseInt(get('minute'))
  };
}

function toDateStr(date, tz) {
  const { year, month, day } = toTZ(date, tz);
  return `${year}-${String(month).padStart(2,'0')}-${String(day).padStart(2,'0')}`;
}

function toTimeStr(date, tz) {
  const { hour, minute } = toTZ(date, tz);
  return `${String(hour).padStart(2,'0')}:${String(minute).padStart(2,'0')}`;
}

function getWeekday(date, tz) {
  const { year, month, day } = toTZ(date, tz);
  return new Date(year, month - 1, day).getDay();
}

function isWeekend(date, tz) {
  const day = getWeekday(date, tz);
  return day === 0 || day === 6;
}

function fromTZComponents(dateStr, hour, minute, tz) {
  const [year, month, day] = dateStr.split('-').map(Number);
  const approxUtc = new Date(Date.UTC(year, month - 1, day, hour, minute));
  for (let offset = -840; offset <= 840; offset++) {
    const candidate = new Date(approxUtc.getTime() + offset * 60000);
    const local = toTZ(candidate, tz);
    if (
      local.year === year &&
      local.month === month &&
      local.day === day &&
      local.hour === hour &&
      local.minute === minute
    ) {
      return candidate;
    }
  }
  return approxUtc;
}

function addDays(date, days) {
  return new Date(date.getTime() + days * 24 * 60 * 60 * 1000);
}

function addMinutes(date, mins) {
  return new Date(date.getTime() + mins * 60 * 1000);
}

// ============================================================
// TIMEZONE MAP
// ============================================================

const timezoneMap = {
  "Eastern Time (ET) — New York": "America/New_York",
  "Central Time (CT) — Chicago": "America/Chicago",
  "Mountain Time (MT) — Denver": "America/Denver",
  "Pacific Time (PT) — Los Angeles": "America/Los_Angeles",
  "Pacific Time (PT) — Vancouver": "America/Vancouver",
  "UK — London": "Europe/London",
  "Central Europe — Paris/Amsterdam": "Europe/Paris",
  "Australia — Sydney": "Australia/Sydney"
};

// ============================================================
// INPUTS
// ============================================================

const formData = $('Form').first().json;
const calendarEvents = $input.all().map(item => item.json);

const LISA_TZ = 'America/Denver';
const clientTZ = timezoneMap[formData['Client Timezone']];
if (!clientTZ) throw new Error(`Unknown timezone: ${formData['Client Timezone']}`);

const clientName = formData['Client Full Name'];
const companyName = formData['Client Company Name'] || '';
const clientEmail = formData['Client Email'];
const clientLastName = clientName.trim().split(' ').pop();
const numberOfSprints = parseInt(formData['Number of Sprints']);
const trelloCardUrl = formData['Trello Card URL'];

const blackoutDates = formData['Client Blackout Dates']
  ? formData['Client Blackout Dates'].split(',').map(d => d.trim())
  : [];

const activateDuration = parseInt(formData['Activate Duration (mins)']) || 90;
const crystallizeDuration = parseInt(formData['Crystallize Duration (mins)']) || 90;
const combinedDuration = formData['Crystallize + Activate Combined (mins) — leave blank if separate']
  ? parseInt(formData['Crystallize + Activate Combined (mins) — leave blank if separate'])
  : null;

const EMPOWER_DURATION = 60;
const EMBED_DURATION = 90;

console.log('Number of sprints:', numberOfSprints);

// ============================================================
// SECURITY CHECKS
// ============================================================

// Access code
if ($('Form').first().json['Access Code'] !== 'YOUR_ACCESS_CODE') {
  throw new Error('Access denied: invalid access code.');
}

// Input validation
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(clientEmail)) {
  throw new Error(`Invalid client email format: "${clientEmail}"`);
}
if (!formData['Client Google Drive Folder URL']?.includes('/folders/')) {
  throw new Error('Client Google Drive Folder URL does not look correct — expected a /folders/ URL.');
}
if (!trelloCardUrl.includes('trello.com/c/')) {
  throw new Error('Trello Card URL does not look correct — expected a trello.com/c/ URL.');
}
for (const d of blackoutDates) {
  if (!/^\d{4}-\d{2}-\d{2}$/.test(d)) {
    throw new Error(`Blackout date "${d}" is not in YYYY-MM-DD format.`);
  }
}

// Duplicate submission check — scoped to same phase
const phaseNumber = parseInt(formData['Phase Number']);
const existingRows = $('Check existing sessions').all()
  .map(i => i.json)
  .filter(r => r['row_number'] > 1 && parseInt(r['Phase #']) === phaseNumber);
if (existingRows.length > 0) {
  const sprints = [...new Set(existingRows.map(r => r['Sprint #']))].sort().join(', ');
  throw new Error(`Client "${clientEmail}" already has sessions scheduled for Phase ${phaseNumber} (Sprint(s): ${sprints}). Use the Reschedule form instead.`);
}

// ============================================================
// BUILD BUSY BLOCKS
// ============================================================

const busyBlocks = [];

for (const event of calendarEvents) {
  if (event.start && event.start.date && !event.start.dateTime) {
    busyBlocks.push({
      dateStr: event.start.date,
      allDay: true
    });
  } else if (event.start && event.start.dateTime) {
    busyBlocks.push({
      start: parseISO(event.start.dateTime),
      end: parseISO(event.end.dateTime),
      allDay: false
    });
  }
}

for (const dateStr of blackoutDates) {
  busyBlocks.push({ dateStr, allDay: true });
}

// ============================================================
// CONFLICT CHECKS
// ============================================================

function isAllDayBlocked(date) {
  const dateStr = toDateStr(date, LISA_TZ);
  return busyBlocks.some(b => b.allDay && b.dateStr === dateStr);
}

function hasTimedConflict(slotStart, slotEnd) {
  return busyBlocks.some(b => {
    if (b.allDay) return false;
    return slotStart < b.end && slotEnd > b.start;
  });
}

function isInClientWindow(slotStart, slotEnd) {
  const clientStartComponents = toTZ(slotStart, clientTZ);
  const clientEndComponents = toTZ(slotEnd, clientTZ);
  const startMins = clientStartComponents.hour * 60 + clientStartComponents.minute;
  const endMins = clientEndComponents.hour * 60 + clientEndComponents.minute;
  return startMins >= 9 * 60 && endMins <= 17 * 60;
}

// ============================================================
// SLOT FINDER
// ============================================================

function findSlot(fromDate, durationMins) {
  const fromDateStr = toDateStr(fromDate, LISA_TZ);
  const currentDay = fromTZComponents(fromDateStr, 0, 0, LISA_TZ);

  for (let dayOffset = 0; dayOffset < 365; dayOffset++) {
    const day = addDays(currentDay, dayOffset);

    if (isWeekend(day, LISA_TZ)) continue;
    if (isAllDayBlocked(day)) continue;

    const dayStr = toDateStr(day, LISA_TZ);

    // Try slots from 11:00am in 30-min increments
    // Latest start = 3pm minus duration
    const latestStartMins = (15 * 60) - durationMins;

    for (let totalMins = 11 * 60; totalMins <= latestStartMins; totalMins += 30) {
      const startHour = Math.floor(totalMins / 60);
      const startMin = totalMins % 60;

      const slotStart = fromTZComponents(dayStr, startHour, startMin, LISA_TZ);
      const slotEnd = addMinutes(slotStart, durationMins);

      if (hasTimedConflict(slotStart, slotEnd)) continue;
      if (!isInClientWindow(slotStart, slotEnd)) continue;

      return { slotStart, slotEnd, dateStr: dayStr };
    }
  }

  return null;
}

// ============================================================
// BUILD SPRINT SESSIONS
// ============================================================

function buildSprintSessions(sprintNumber, firstSessionDate) {
  const sessions = [];
  const useCombined = combinedDuration !== null;

  const isFirstOfPhase = (sprintNumber - 1) % 4 === 0;

const sequence = isFirstOfPhase
    ? (useCombined
        ? [
            { type: 'Crystallize+Activate', duration: combinedDuration, includesLisa: true },
            { type: 'Empower', duration: EMPOWER_DURATION, includesLisa: true },
            { type: 'Embed', duration: EMBED_DURATION, includesLisa: true }
          ]
        : [
            { type: 'Crystallize', duration: crystallizeDuration, includesLisa: true },
            { type: 'Activate', duration: activateDuration, includesLisa: true },
            { type: 'Empower', duration: EMPOWER_DURATION, includesLisa: true },
            { type: 'Embed', duration: EMBED_DURATION, includesLisa: true }
          ])
    : [
        { type: 'Activate', duration: activateDuration, includesLisa: true },
        { type: 'Empower', duration: EMPOWER_DURATION, includesLisa: true },
        { type: 'Embed', duration: EMBED_DURATION, includesLisa: true }
      ];

  let searchFrom = firstSessionDate;
  let firstSessionActual = null;

  for (let i = 0; i < sequence.length; i++) {
    const session = sequence[i];

    // Enforce 21-day minimum from first session to Embed
    if (session.type === 'Embed' && firstSessionActual) {
      const earliestEmbed = addDays(firstSessionActual, 21);
      if (searchFrom < earliestEmbed) {
        searchFrom = earliestEmbed;
      }
    }

    const result = findSlot(searchFrom, session.duration);
    if (!result) {
      throw new Error(`No slot found for Sprint ${sprintNumber} — ${session.type} after ${toDateStr(searchFrom, LISA_TZ)}`);
    }

    const { slotStart, slotEnd, dateStr } = result;
    if (session.type === 'Activate' || session.type === 'Crystallize+Activate') {
      firstSessionActual = slotStart;
    }

    const sessionId = `VC-${clientLastName}-S${sprintNumber}-${session.type.replace('+', '')}`;

    sessions.push({
      sessionId,
      clientName,
      companyName,
      clientEmail,
      trelloCardUrl,
      sprintNumber,
      sessionType: session.type,
      dateISO: dateStr,
      startTimeMT: toTimeStr(slotStart, LISA_TZ),
      endTimeMT: toTimeStr(slotEnd, LISA_TZ),
      startTimeClient: toTimeStr(slotStart, clientTZ),
      endTimeClient: toTimeStr(slotEnd, clientTZ),
      clientTimezone: clientTZ,
      durationMins: session.duration,
      includesLisa: session.includesLisa,
      calendarEventId: null
    });

    // Next session minimum 7 days later
    searchFrom = addDays(slotStart, 7);
  }

  return sessions;
}

