const allSessions = [];
const startDateStr = formData['Sprint Start Date'];
let nextSprintStart = startDateStr ? new Date(startDateStr + 'T12:00:00Z') : new Date();

for (let sprint = 1; sprint <= numberOfSprints; sprint++) {
  const sprintSessions = buildSprintSessions(sprint, nextSprintStart);
  allSessions.push(...sprintSessions);

  const lastSession = sprintSessions[sprintSessions.length - 1];
  nextSprintStart = addDays(
    fromTZComponents(lastSession.dateISO, 0, 0, LISA_TZ),
    7
  );
}

return allSessions.map(session => ({ json: session }));

// Get the copied Doc ID
