    });
    replacements.push({
      find: `{{S${s}_R${row}_SESSION}}`,
      replace: sessionLabel(session.sessionType)
    });
    replacements.push({
      find: `{{S${s}_R${row}_TIME}}`,
      replace: formatTime(session.startTimeMT, session.endTimeMT)
    });
  });

  // Fill remaining empty rows with a space
  for (let row = sprintSessions.length + 1; row <= 4; row++) {
    replacements.push({ find: `{{S${s}_R${row}_DATE}}`, replace: ' ' });
    replacements.push({ find: `{{S${s}_R${row}_SESSION}}`, replace: ' ' });
    replacements.push({ find: `{{S${s}_R${row}_TIME}}`, replace: ' ' });
  }
}

// Increase when second template page is added for Phase 2+
const MAX_TEMPLATE_SPRINTS = 9;

// Fill all unhandled sprints with spaces
const handledSprints = new Set(Object.keys(bySprint).map(Number));
for (let s = 1; s <= MAX_TEMPLATE_SPRINTS; s++) {
  if (!handledSprints.has(s)) {
    for (let row = 1; row <= 4; row++) {
      replacements.push({ find: `{{S${s}_R${row}_DATE}}`, replace: ' ' });
      replacements.push({ find: `{{S${s}_R${row}_SESSION}}`, replace: ' ' });
      replacements.push({ find: `{{S${s}_R${row}_TIME}}`, replace: ' ' });
    }
  }
}

// Build Google Docs batchUpdate request body
const requests = replacements.map(r => ({
  replaceAllText: {
    containsText: {
      text: r.find,
      matchCase: true
    },
    replaceText: r.replace
  }
}));

return [{
  json: {
    docId,
    secret: 'YOUR_DOC_REPLACER_SECRET',
    requestBody: { requests }
  }
}];

