// BUILD SPRINT SESSIONS
// ============================================================

function buildSprintSessions(sprintNumber, firstSessionDate) {
  const sessions = [];
  const useCombined = combinedDuration !== null;
  const isFirstOfPhase = (sprintNumber - 1) % 4 === 0;

  const sequence = isFirstOfPhase
    ? (useCombined
        ? [
            { type: 'Crystallize+Activate', duration: combinedDuration, includesLisa: true },
            { type: 'Empower', duration: EMPOWER_DURATION, includesLisa: true },
            { type: 'Embed', duration: EMBED_DURATION, includesLisa: true }
          ]
        : [
            { type: 'Crystallize', duration: crystallizeDuration, includesLisa: true },
            { type: 'Activate', duration: activateDuration, includesLisa: true },
            { type: 'Empower', duration: EMPOWER_DURATION, includesLisa: true },
            { type: 'Embed', duration: EMBED_DURATION, includesLisa: true }
          ])
    : [
        { type: 'Activate', duration: activateDuration, includesLisa: true },
        { type: 'Empower', duration: EMPOWER_DURATION, includesLisa: true },
        { type: 'Embed', duration: EMBED_DURATION, includesLisa: true }
      ];

  let searchFrom = firstSessionDate;
  let firstSessionActual = null;

  for (let i = 0; i < sequence.length; i++) {
    const session = sequence[i];

    if (session.type === 'Embed' && firstSessionActual) {
      const earliestEmbed = addDays(firstSessionActual, 21);
      if (searchFrom < earliestEmbed) {
        searchFrom = earliestEmbed;
      }
    }

    const result = findSlot(searchFrom, session.duration);
    if (!result) {
      throw new Error(`No slot found for Sprint ${sprintNumber} — ${session.type} after ${toDateStr(searchFrom, LISA_TZ)}`);
    }

    const { slotStart, slotEnd, dateStr } = result;
    if (session.type === 'Activate' || session.type === 'Crystallize+Activate') {
      firstSessionActual = slotStart;
    }

    const sessionId = `VC-${clientLastName}-S${sprintNumber}-${session.type.replace('+', '')}`;

    sessions.push({
      sessionId,
      clientName,
      companyName,
      clientEmail,
      trelloCardUrl,
      sprintNumber,
      sessionType: session.type,
      dateISO: dateStr,
      startTimeMT: toTimeStr(slotStart, LISA_TZ),
      endTimeMT: toTimeStr(slotEnd, LISA_TZ),
      startTimeClient: toTimeStr(slotStart, clientTZ),
      endTimeClient: toTimeStr(slotEnd, clientTZ),
      clientTimezone: clientTZ,
      durationMins: session.duration,
      includesLisa: session.includesLisa,
      calendarEventId: null,
      blackoutDatesStr: blackoutDates.join(', ')
    });

    searchFrom = addDays(slotStart, 7);
  }

  return sessions;
}

