  for (let row = sprintRows.length + 1; row <= 4; row++) {
    replacements.push({ find: `{{S${s}_R${row}_DATE}}`, replace: ' ' });
    replacements.push({ find: `{{S${s}_R${row}_SESSION}}`, replace: ' ' });
