  // Fill remaining empty rows with a space
  for (let row = sprintSessions.length + 1; row <= 4; row++) {
    replacements.push({ find: `{{S${s}_R${row}_DATE}}`, replace: ' ' });
    replacements.push({ find: `{{S${s}_R${row}_SESSION}}`, replace: ' ' });
    replacements.push({ find: `{{S${s}_R${row}_TIME}}`, replace: ' ' });
  }
}

// Fill all unhandled sprints with spaces
const handledSprints = new Set([...Object.keys(keptBySprint), ...Object.keys(bySprint)].map(Number));
for (let s = 1; s <= MAX_TEMPLATE_SPRINTS; s++) {
  if (!handledSprints.has(s)) {
    for (let row = 1; row <= 4; row++) {
      replacements.push({ find: `{{S${s}_R${row}_DATE}}`, replace: ' ' });
      replacements.push({ find: `{{S${s}_R${row}_SESSION}}`, replace: ' ' });
      replacements.push({ find: `{{S${s}_R${row}_TIME}}`, replace: ' ' });
    }
  }
}

